/// @notice Minimal local interface for the zipUSD `ESynth` burn seam used by the `ZipRedemptionQueue`.
/// @dev zipUSD = Euler `ESynth` (18-dp). Verified against `reference/euler-vault-kit/src/Synths/ESynth.sol:81`:
interface IZipUSD {
    function burn(address burnFrom, uint256 amount) external;
}

interface IEulerEarn {
    function deposit(uint256 assets, address receiver) external returns (uint256 shares);

    function redeem(uint256 shares, address receiver, address owner) external returns (uint256 assets);

    function convertToAssets(uint256 shares) external view returns (uint256 assets);

    function balanceOf(address account) external view returns (uint256);

    function asset() external view returns (address);
}

address lien = ILienTokenFactory(lienFactory).create(p.lienId);
if (lien != ILienTokenFactory(lienFactory).computeAddress(p.lienId, address(this))) revert PrecomputeMismatch();

// 3: custody approve — exactly 1e18 (no standing allowance left, F-7).
ILienToken(lien).approve(venue_, FULL_LIEN);

// 4: open the line with the FULL lien (the venue backstops != 1e18); oracleKey == lien by construction.
(address lineRef, address oracleKey) = IZipcodeVenue(venue_).openLine(p.lienId, lien, FULL_LIEN);

IZipcodeOracleRegistry(oracleRegistry).seedPrice(oracleKey, p.equityMark, p.sourceTs);
IZipcodeVenue(venue_).setLineLimits(lineRef, p.borrowLTV, p.liqLTV, p.cap);
IZipcodeVenue(venue_).fund(lineRef, p.drawAmount);
IZipcodeVenue(venue_).draw(lineRef, p.drawAmount, erebor);

// step 0: fresh per-line borrower account + its operator grant (the adapter is the granted operator).
LineAccount la = new LineAccount{salt: lienId}(address(evc), address(this));
address borrowAccount = address(uint160(address(la)) ^ 1);

// step 1: escrow collateral vault (bare holding box: no oracle, no unit-of-account, no governance).
address collat =
    eVaultFactory.createProxy(address(0), false, abi.encodePacked(lienToken, address(0), address(0)));
IEVault(collat).setHookConfig(address(0), 0);
IEVault(collat).setGovernorAdmin(address(0));

// step 2: dedicated per-line router; wire COLLAT -> lienToken -> registry (the adapter is governor at birth).
EulerRouter router = new EulerRouter(address(evc), address(this));
router.govSetResolvedVault(collat, true); // unwrap escrow shares -> lienToken, 1:1
router.govSetConfig(lienToken, usdc, oracleRegistry); // price (lienToken, USDC) via the registry

constructor(address evc_, address operator_) {
    // Sub-account 1 of this contract's own prefix: shares the 19-byte prefix, and is code-free (a plain
    // account address, not this contract's coded address) so the EVC's non-owner-must-be-code-free guard
    // (EthereumVaultConnector.sol:787) does NOT trip on the operator path.
    address borrowAccount = address(uint160(address(this)) ^ 1);

    // Owner-self path: authenticateCaller(borrowAccount, allowOperator:true) finds the shared prefix, registers
    // this contract as the prefix owner, then sets the operator bit for `operator_` over sub-account 1.
    IEVC(evc_).setAccountOperator(borrowAccount, operator_, true);
}

fallback() external {
    address caller = _msgSender();
    if (!evc.isAccountOperatorAuthorized(caller, borrowDriver)) revert NotAuthorizedOperator();
}

function _msgSender() internal view returns (address msgSender) {
    if (!eVaultFactory.isProxy(msg.sender)) return msg.sender;

    assembly {
        msgSender := shr(96, calldataload(sub(calldatasize(), 20)))
    }
}

function create(bytes32 lienId) external returns (address lien) {
    bytes32 salt = keccak256(abi.encode(lienId));
    bytes memory initCode =
        abi.encodePacked(type(LienCollateralToken).creationCode, abi.encode(msg.sender));
    lien = Create2.deploy(0, salt, initCode);
    emit LienCreated(lienId, lien);
}

/// @notice Shared write guards (fail-closed): price != 0, price <= uint208.max, ts <= now, decimals() == 18.
function _writePrice(address lien, uint256 price, uint48 ts) internal {
    if (price == 0) revert Errors.PriceOracle_InvalidAnswer();
    if (price > type(uint208).max) revert Errors.PriceOracle_Overflow();
    if (ts > block.timestamp) revert FutureTimestamp();
    if (ts <= cache[lien].timestamp) revert StaleReport(); // strictly-newer (first write: timestamp==0 passes); covers seedPrice clobber + out-of-order rt-3
    if (_strictDecimals(lien) != LIEN_DECIMALS) revert InvalidLienDecimals(lien);
    cache[lien] = Cache({price: uint208(price), timestamp: ts});
}

} else if (opType == REDEEM) {
    uint256 shares = abi.decode(payload, (uint256));
    to = eePool;
    data = abi.encodeWithSelector(IEulerEarn.redeem.selector, shares, warehouseSafe, warehouseSafe);
} else if (opType == REPAY) {
    (address dest, uint256 amount) = abi.decode(payload, (address, uint256));
    if (dest != redemptionBox) revert WrongRedemptionBox(dest);
    to = usdc;
    data = abi.encodeWithSelector(IERC20.transfer.selector, redemptionBox, amount);
} else {
    revert UnsupportedOpType(opType);
}
bool ok = roles.execTransactionWithRole(to, 0, data, OP_CALL, roleKey, true);
if (!ok) revert RoleExecFailed();

function deposit(uint256 usdcIn) external nonReentrant returns (uint256 zipMinted) {
    if (usdcIn == 0) revert ZeroAmount();
    IERC20(usdc).safeTransferFrom(msg.sender, address(this), usdcIn);
    zipMinted = usdcIn * scaleUp;
    IESynth(zipUSD).mint(msg.sender, zipMinted); // capacity-gated; mint(·,0) is a no-op (the ZeroAmount guard covers it)
    IERC20(usdc).forceApprove(eePool, usdcIn);
    IEulerEarn(eePool).deposit(usdcIn, warehouseSafe); // shares -> warehouseSafe Safe; the module never holds shares
    emit Deposited(msg.sender, usdcIn, zipMinted);
}

uint256 pending = totalPending;
uint256 availableAssets = IERC20(usdc).balanceOf(address(this)) - reservedAssets; // free REPAY USDC
uint256 maxFillAssets = pending / scaleUp; // par capacity (floor)
uint256 fillAssets = availableAssets < maxFillAssets ? availableAssets : maxFillAssets;
uint256 filledShares = fillAssets * scaleUp; // <= pending, EXACT multiple of scaleUp

if (filledShares != 0) {
    address r = pendingRequester;
    totalPending = pending - filledShares;
    pendingShares[r] -= filledShares;
    claimableAssets[r] += fillAssets; // par, round DOWN (KR-5)
    reservedAssets += fillAssets;
    if (pendingShares[r] == 0) pendingRequester = address(0); // fully drained
    IZipUSD(zipUSD).burn(address(this), filledShares);

// topology assert (Key req 2): the exact 6-clause web. All clauses must hold; the silo must point only at
// its OWN components (curator/juniorBasket carried for routing only — NOT asserted).
if (
    IFreeze(cfg.freeze).eulerEarn() != cfg.eePool || IFreeze(cfg.freeze).warehouseSafe() != cfg.warehouseSafe
        || IFreeze(cfg.freeze).navOracle() != cfg.navOracle
        || IEscrow(cfg.escrow).coordinator() != cfg.defaultCoordinator
        || INavWriter(cfg.defaultCoordinator).navOracle() != cfg.navOracle
        || ISeniorVenue(cfg.adapter).seniorPool() != cfg.eePool
) revert SiloMiswired();

function _default(bytes memory data) internal {
    (bytes32 lienId, uint256 atRisk) = abi.decode(data, (bytes32, uint256));
    if (lienLoss[lienId].status != LienStatus.Bonded) revert BadStatus();
    if (atRisk == 0) revert ZeroAtRisk();

    uint256 p = atRisk * (1e18 - recoveryFloor) / 1e18;
    lienLoss[lienId].provision = p;
    lienLoss[lienId].status = LienStatus.Defaulted;
    totalProvision += p;

    navOracle.writeProvision(totalProvision);

    emit Defaulted(lienId, atRisk, p);
}

navOracle.poke();
uint256 navE = navOracle.navEntry(); // reverts StalePrice if a required leg is stale (issuance pauses)
uint256 value = navOracle.valueOf(asset, amount); // the Gate owns valuation; no caller asserts a price
if (navOracle.grossBasketValue() + value > tvlCap) revert TvlCapExceeded();

shares = value * 1e18 / navE; // round DOWN (favor the vault)
if (shares == 0) revert ZeroShares();

uint256 basketBefore = IERC20(asset).balanceOf(juniorTrancheSafe);
IERC20(asset).safeTransferFrom(msg.sender, juniorTrancheSafe, amount);
if (IERC20(asset).balanceOf(juniorTrancheSafe) - basketBefore != amount) revert TransferShortfall();

// Mint Loot to the Gate (manager(2)) + transferable szipUSD to the receiver — paired, equal amounts.
baal.mintLoot(_one(address(this)), _one(shares));
SzipUSD(shareToken).mint(receiver, shares);

function navEntry() external view returns (uint256) {
    if (_legStale(LEG_ALPHA_USD)) revert StalePrice(LEG_ALPHA_USD);
    if (_legStale(LEG_HYDX_USD)) revert StalePrice(LEG_HYDX_USD);
    if (xAlphaRateOracle != address(0) && !IXAlphaRateFresh(xAlphaRateOracle).fresh()) revert StaleRate();
    uint256 s = spotNavPerShare();
    uint256 t = twapNavPerShare();
    return s > t ? s : t;
}

/// @notice The exit price `min(spot, twap)`. Does NOT revert on staleness (prices off the last good mark).
function navExit() external view returns (uint256) {
    uint256 s = spotNavPerShare();
    uint256 t = twapNavPerShare();
    return s < t ? s : t;
}
